#!/usr/bin/env bash
# adapters/mkdocs.sh — MkDocs Material build adapter
set -euo pipefail
info() { echo "[book-engine:mkdocs] $*" >&2; }

# Install MkDocs + Material theme
if ! python3 -c "import mkdocs" 2>/dev/null; then
    info "Installing MkDocs + Material..."
    pip install mkdocs==1.6.0 mkdocs-material==9.5.18 --quiet
fi

# mkdocs.yml was generated by export.sh before this adapter runs
[[ -f mkdocs.yml ]] || { echo "[book-engine:mkdocs] mkdocs.yml not found" >&2; exit 1; }

# MkDocs requires docs_dir to point at the source
# Patch docs_dir into the generated mkdocs.yml
if ! grep -q "^docs_dir:" mkdocs.yml; then
    sed -i "1a docs_dir: ${BOOK_SRC}" mkdocs.yml
fi

mkdir -p "${BOOK_OUT}/mkdocs"
info "Running: mkdocs build --site-dir ${BOOK_OUT}/mkdocs"
mkdocs build --site-dir "${BOOK_OUT}/mkdocs" --quiet
info "MkDocs output: ${BOOK_OUT}/mkdocs/"
